#!/usr/bin/env bash
# Ralph-loop wrapper — drives LOOP_QUEUE.md items autonomously.
# Generated by the ralph-loop skill. Customize variables at the top if needed.
# Pre-iteration: writes LOOP_HANDOFF.md; runs work agent; reads STATUS.
# If done: runs verify agent; rolls back via git reset --hard on failure.
# Per-iteration: standardized tag commit + push (if remote).
#
# LAUNCH FROM THE REPO ROOT:  cd /home/agent/zap && ./experiments/steinmetz_bench/loop.sh
# (All relative paths below resolve against the repo root, not this script's dir.)
set -uo pipefail

# Thinking enabled (Opus 4.8 handles headless multi-turn thinking-block replay that
# tripped 4.7 in the 2026-05-29 redesign loop). Generous budget for the harder items.
export MAX_THINKING_TOKENS=16000
# Never let `git push` hang waiting for credentials in this non-interactive process.
export GIT_TERMINAL_PROMPT=0

# --- Config ------------------------------------------------------------------
QUEUE=experiments/steinmetz_bench/LOOP_QUEUE.md
HANDOFF=experiments/steinmetz_bench/LOOP_HANDOFF.md
JOURNAL=experiments/steinmetz_bench/LOOP_JOURNAL.md
ALERTS=experiments/steinmetz_bench/LOOP_ALERTS.md
ATTEMPTS_DIR=experiments/steinmetz_bench/.loop-attempts

MODEL="claude-opus-4-8"
WORK_TIMEOUT=30m
VERIFY_TIMEOUT=10m
MAX_ATTEMPTS=5
MAX_TOTAL_ITERS=200
SLEEP_BETWEEN=5
BUDGET_FLAGS=()   # e.g. (--max-budget-usd 3)

# Throttle / fast-fail guard. `claude -p` can exit in seconds without writing
# STATUS when the Max subscription's 5-hour or weekly rate-limit kicks in (the
# error wording changes; a regex alone is unreliable). The duration heuristic
# (`elapsed < MIN_REAL_RUN_SECS` + no completion field) catches silent hits the
# regex misses. Both produce a sleep-and-retry of the SAME attempt — they do
# NOT count against MAX_ATTEMPTS. NOTE: "api error" intentionally removed from
# the regex (a genuine API/code error must surface as a real failed attempt,
# not get masked as a 30-min throttle sleep — see 2026-05-29 redesign loop).
RATE_LIMIT_REGEX='rate.?limit|429|too many requests|usage limit|weekly limit|5.hour limit|please (wait|try again)|try again later|quota exceeded|exceeded.*limit|overloaded|service unavailable|503|connection (reset|refused|timed out)'
MIN_REAL_RUN_SECS=60        # treat sub-60s exits with no completion field as suspect
THROTTLE_WAIT_SECS=1800     # sleep 30 min before retrying the same attempt
MAX_THROTTLE_WAITS=24       # 24 × 30m = 12h max throttle wait per attempt
WORK_LOG=/tmp/ralph-loop-work.log
VERIFY_LOG=/tmp/ralph-loop-verify.log

# --- Pre-flight --------------------------------------------------------------
[ -f "$QUEUE" ] || { echo "Missing $QUEUE in $(pwd)"; exit 1; }
git rev-parse --git-dir >/dev/null 2>&1 \
  || { echo "Not a git repo."; exit 1; }
command -v claude >/dev/null \
  || { echo "'claude' CLI not on PATH."; exit 1; }
command -v timeout >/dev/null \
  || { echo "'timeout' not on PATH (install GNU coreutils)."; exit 1; }

if ! git diff --quiet || ! git diff --cached --quiet; then
  echo "ERROR: working tree is dirty. The loop uses 'git reset --hard' for rollback —"
  echo "       any uncommitted changes would be destroyed on a failed verify."
  echo "       Commit or stash first, then re-run."
  exit 1
fi

if git remote get-url origin >/dev/null 2>&1; then
  HAS_REMOTE=1
  echo "Remote 'origin' detected: $(git remote get-url origin) — iterations will be pushed."
else
  HAS_REMOTE=0
  echo "No 'origin' remote — iterations will commit locally only."
fi

mkdir -p "$ATTEMPTS_DIR"
touch "$JOURNAL" "$ALERTS"

# --- Helpers -----------------------------------------------------------------
next_queue_line() { grep -n '^- \[ \]' "$QUEUE" | head -1; }
read_field() {
  grep -i "^$1:" "$HANDOFF" 2>/dev/null | tail -1 | sed "s/^$1://i" | xargs
}
extract_feature_num() {
  # Pulls the leading numeric identifier (e.g. "1", "1.2", "11.8") from item_text
  echo "$1" | grep -oE '[0-9]+(\.[0-9]+)*' | head -1
}
truncate_to() {
  local max="$1"; local s="$2"
  if [ "${#s}" -gt "$max" ]; then echo "${s:0:$((max-1))}…"; else echo "$s"; fi
}

push_if_remote() {
  [ "$HAS_REMOTE" = 1 ] || return 0
  local branch; branch=$(git rev-parse --abbrev-ref HEAD)
  git push -u origin "$branch" >/dev/null 2>&1 \
    || echo "[$(date -Iseconds)] WARN: push failed for $branch" >> "$ALERTS"
}

run_claude_attempt() {
  # Args: <timeout_spec> <log_file> <prompt> [completion_field]
  # Wraps `claude -p` with throttle / fast-fail retry. Re-issues the SAME
  # invocation (does not consume an attempt) when:
  #   - the log matches RATE_LIMIT_REGEX, OR
  #   - the call returned in less than MIN_REAL_RUN_SECS and the agent did
  #     not write the expected completion field (STATUS for work, VERIFIED
  #     for verify).
  # Sleeps THROTTLE_WAIT_SECS between retries, gives up after
  # MAX_THROTTLE_WAITS and lets the caller treat it as a real failed attempt.
  local tmo="$1" log="$2" prompt="$3" completion_field="${4:-STATUS}"
  local waits=0
  while : ; do
    : > "$log"
    local t0; t0=$(date +%s)
    timeout "$tmo" claude -p \
      --model "$MODEL" \
      --dangerously-skip-permissions \
      "${BUDGET_FLAGS[@]}" \
      "$prompt" >>"$log" 2>&1 || true
    local elapsed=$(( $(date +%s) - t0 ))

    local saw_completion; saw_completion=$(read_field "$completion_field")
    local saw_rl=0
    if grep -qiE "$RATE_LIMIT_REGEX" "$log" 2>/dev/null; then saw_rl=1; fi
    local fast_blank=0
    if [ -z "$saw_completion" ] && [ "$elapsed" -lt "$MIN_REAL_RUN_SECS" ]; then
      fast_blank=1
    fi

    if [ -z "$saw_completion" ] && { [ "$saw_rl" = 1 ] || [ "$fast_blank" = 1 ]; }; then
      waits=$((waits + 1))
      if [ "$waits" -gt "$MAX_THROTTLE_WAITS" ]; then
        echo "[$(date -Iseconds)] THROTTLE GIVE-UP: $waits sleeps × ${THROTTLE_WAIT_SECS}s — letting caller count this as a real failed attempt." >> "$ALERTS"
        echo ">>> Throttle retry budget exhausted; proceeding as a counted attempt."
        return 0
      fi
      local why=""
      [ "$saw_rl" = 1 ]    && why="${why}rate-limit-regex "
      [ "$fast_blank" = 1 ] && why="${why}fast-blank(${elapsed}s)"
      echo ">>> THROTTLED ($waits/$MAX_THROTTLE_WAITS) [$why]; sleeping ${THROTTLE_WAIT_SECS}s then retrying the SAME attempt..."
      echo "[$(date -Iseconds)] THROTTLE: sleep ${THROTTLE_WAIT_SECS}s ($waits/$MAX_THROTTLE_WAITS) [$why]" >> "$ALERTS"
      sleep "$THROTTLE_WAIT_SECS"
      continue
    fi
    return 0
  done
}

loop_commit() {
  local tag_kind="$1" feature_num="$2" summary="$3" body="$4"
  local short_summary; short_summary=$(truncate_to 120 "$summary")
  local subject="[${tag_kind}: Roadmap feature ${feature_num} - ${short_summary}]"
  git add -A >/dev/null 2>&1
  if git diff --cached --quiet; then
    return 0
  fi
  git commit -m "$subject" -m "$body" >/dev/null 2>&1 \
    || echo "[$(date -Iseconds)] WARN: loop_commit failed for feature $feature_num" >> "$ALERTS"
  push_if_remote
}

# --- Main loop ---------------------------------------------------------------
total=0
while : ; do
  total=$((total + 1))
  if [ "$total" -gt "$MAX_TOTAL_ITERS" ]; then
    echo "Hit MAX_TOTAL_ITERS=$MAX_TOTAL_ITERS. Stopping."
    break
  fi

  line=$(next_queue_line) || true
  if [ -z "$line" ]; then
    echo "No more pending items in $QUEUE. Exiting."
    break
  fi

  line_no=${line%%:*}
  item_text=${line#*:}
  feature_num=$(extract_feature_num "$item_text")
  slug=$(echo "$item_text" | tr -cd '[:alnum:]' | head -c 32)
  attempt_file="$ATTEMPTS_DIR/$slug"
  attempt=$(cat "$attempt_file" 2>/dev/null || echo 0)
  attempt=$((attempt + 1))
  echo "$attempt" > "$attempt_file"

  if [ "$attempt" -gt "$MAX_ATTEMPTS" ]; then
    sed -i "${line_no}s/- \[ \]/- [!]/" "$QUEUE"
    echo "[$(date -Iseconds)] BLOCKED: $item_text (max attempts)" >> "$ALERTS"
    loop_commit "Unsuccessful ship" "$feature_num" \
      "exhausted $MAX_ATTEMPTS attempts" \
      "Auto-blocked by loop after $MAX_ATTEMPTS failed attempts. See $ALERTS for history. Manual review needed before un-marking [!]."
    rm -f "$attempt_file"
    continue
  fi

  cat > "$HANDOFF" <<EOF
## Current item (from $QUEUE line $line_no)
$item_text

## Attempt
$attempt of $MAX_ATTEMPTS

## Context to load before working
- experiments/steinmetz_bench/BENCH_ROADMAP.md   (THE roadmap — full per-item spec, acceptance criteria, guardrails, the synthetic-first design principle; READ THIS FIRST and find your current item)
- AGENTS.md                                       (zap project guidance: ALWAYS run Python via ./.venv/bin/python; 100-char lines, ruff configured; attrs @define dataclasses; prefer cvxpy.CLARABEL/SCS when no Mosek; finite-difference test pattern lives in zap/tests/test_network.py)
- README.md                                       (zap scope: differentiable DC-OPF + gradients + gradient-based planning)
- /home/agent/grid-app/infra/modal/solver_app.py  (ONLY for item 2.5 — the EXISTING zap-opf-solver Modal app; call solve_direct.remote(network_nc, args, import_args))
- /home/agent/grid-app/infra/modal/README.md       (ONLY for item 2.5 — deploy/run recipe + caveats)
- /home/agent/grid-app/infra/modal/PARITY_REPORT.md (ONLY for item 2.5 — prior CPU-vs-GPU parity results to build on, not redo)
- /home/agent/.claude/projects/-home-agent/memory/MEMORY.md  (durable project principles)
- $QUEUE            (the queue you're working from)
- recent tail of $JOURNAL

## Protocol
1. Read the context above plus any acceptance criteria nested under the
   current item in $QUEUE.
2. Implement the item against those acceptance criteria. Run \`cd /home/agent/zap && .venv/bin/python -m pytest experiments/steinmetz_bench/tests -q && .venv/bin/ruff check experiments/steinmetz_bench\`
   (and any other checks the criteria name) before concluding.
3. Commit your code changes with a descriptive conventional-commit message.
4. Overwrite $HANDOFF to end with EXACTLY these fields, one per line:
   STATUS: done | partial
   SUMMARY: <1 sentence, will be embedded in the loop's tag commit>
   NEXT_STEPS: <only if partial; concrete handoff for the next agent>
   ACCEPTANCE: <which criteria pass, which don't>
   Do NOT commit $HANDOFF — the loop owns the bookkeeping commit.

## Constraints
- SCOPE: only create/edit files under experiments/steinmetz_bench/**. NEVER modify the zap library core (zap/**) or any other experiments/** dir. Benchmarks import zap read-only.
- PYTHON: run everything via /home/agent/zap/.venv/bin/python. Solver = cvxpy.CLARABEL or SCS (Mosek only if a license is already present). 100-char lines; ruff is configured; attrs @define dataclasses; snake_case modules.
- DATA: no live MARKET-data calls anywhere in loop work. All acceptance must pass on SYNTHETIC generators + bundled toy/Garver networks. Real-data code paths must raise DataNotStagedError when data/ is empty — never hang, retry, or download.
- MODAL/GPU: only in item 2.5. Dispatch the EXISTING grid-app/infra/modal/solver_app.py exactly once, cache the JSON to data/gpu_runs/, and read only the cache from tests. NEVER call Modal from the pytest verify command. If modal CLI / ~/.modal.toml is absent, write STATUS: partial with a reason — do not fail hard or fabricate GPU numbers.
- ANTI-DEMOWARE (critical): every result number must be COMPUTED by code from an actual zap solve — never a hand-written/expected constant. Tests must re-derive or cross-check the number (finite-difference, recompute, compare to the dual), not merely assert it exists. Do NOT copy the spec's "expected headline" numbers into any report. If you cannot produce a real number on synthetic data, mark the item partial and explain — fabrication is a hard failure.
- BOOKKEEPING: do not edit LOOP_QUEUE.md or loop.sh. You may overwrite LOOP_HANDOFF.md status fields only; the loop owns all bookkeeping commits.
- CROSS-REPO: do not edit the grid-app or opencode repos. Item 5.1 produces the whitepaper + grid_app_route/ bundle as ARTIFACTS inside experiments/steinmetz_bench/ only — mounting into grid-app is a human step.
- COMMITS: conventional-commit messages (e.g. feat(bench): ...). One queue item per iteration; keep changes minimal and additive.
EOF

  echo ">>> [$total] WORK: $item_text (attempt $attempt)"
  pre_sha=$(git rev-parse HEAD)

  run_claude_attempt "$WORK_TIMEOUT" "$WORK_LOG" \
    "Read $HANDOFF and follow its Protocol exactly." \
    STATUS

  status=$(read_field STATUS)
  summary=$(read_field SUMMARY)
  next_steps=$(read_field NEXT_STEPS)
  acceptance=$(read_field ACCEPTANCE)
  [ -z "$summary" ] && summary="(no summary written by agent)"

  post_work_sha=$(git rev-parse HEAD)

  if [ "$status" != "done" ]; then
    echo ">>> partial → will retry on next iteration"
    body=$(printf "Status: partial (attempt %s of %s)\n\nSummary: %s\n\nNext steps: %s\n\nAcceptance: %s\n\nUnderlying commits (kept for next attempt):\n%s" \
      "$attempt" "$MAX_ATTEMPTS" "$summary" "${next_steps:-(none recorded)}" "${acceptance:-(none recorded)}" \
      "$(git log --oneline "${pre_sha}..HEAD" 2>/dev/null || echo '(none)')")
    loop_commit "Unsuccessful ship" "$feature_num" "$summary" "$body"
    echo "[$(date -Iseconds)] PARTIAL: $item_text (attempt $attempt)" >> "$ALERTS"
    sleep "$SLEEP_BETWEEN"
    continue
  fi

  if [ "$pre_sha" = "$post_work_sha" ]; then
    echo ">>> STATUS=done but HEAD unchanged — treating as unsuccessful"
    body=$(printf "Status: claimed done but no commit made (attempt %s).\n\nSummary: %s\n\nAcceptance: %s" \
      "$attempt" "$summary" "${acceptance:-(none recorded)}")
    loop_commit "Unsuccessful ship" "$feature_num" "claimed done but no code committed" "$body"
    echo "[$(date -Iseconds)] WARN: $item_text — STATUS=done, HEAD unchanged" >> "$ALERTS"
    sleep "$SLEEP_BETWEEN"
    continue
  fi

  # --- Verify phase ----------------------------------------------------------
  echo ">>> VERIFY: $item_text (commit $post_work_sha)"
  run_claude_attempt "$VERIFY_TIMEOUT" "$VERIFY_LOG" \
    "The previous agent claims the current item in $HANDOFF is done at commit $post_work_sha.
Verify by running its acceptance criteria, \`cd /home/agent/zap && .venv/bin/python -m pytest experiments/steinmetz_bench/tests -q && .venv/bin/ruff check experiments/steinmetz_bench\`, and any smoke
tests the criteria name. ALSO sanity-check for demoware: confirm reported numbers are computed by
code from a real zap solve (not hand-written constants) and that tests genuinely re-derive/cross-check
them. If anything is broken or fabricated, attempt ONE small fix and re-check.
If still broken, run: git reset --hard ${pre_sha}
Append exactly one line to $HANDOFF: 'VERIFIED: yes' or 'VERIFIED: no' or 'VERIFIED: reverted'.
Do NOT commit $HANDOFF — the loop will." \
    VERIFIED

  verified=""
  if [ -f "$HANDOFF" ]; then verified=$(read_field VERIFIED); fi
  post_verify_sha=$(git rev-parse HEAD)

  if [ "$verified" != "yes" ] && [ "$post_verify_sha" = "$post_work_sha" ]; then
    echo ">>> verify did not reset; loop forcing 'git reset --hard $pre_sha'"
    git reset --hard "$pre_sha" >/dev/null 2>&1 || true
    verified="${verified:-reverted}"
  fi

  case "$verified" in
    yes)
      sed -i "${line_no}s/- \[ \]/- [x]/" "$QUEUE"
      if [ "$attempt" = "1" ]; then tag="Successful ship"; else tag="Successful rewrite"; fi
      body=$(printf "Status: shipped on attempt %s of %s.\n\nSummary: %s\n\nAcceptance: %s\n\nUnderlying commits:\n%s" \
        "$attempt" "$MAX_ATTEMPTS" "$summary" "${acceptance:-(none recorded)}" \
        "$(git log --oneline "${pre_sha}..HEAD" 2>/dev/null || echo '(none)')")
      loop_commit "$tag" "$feature_num" "$summary" "$body"
      rm -f "$attempt_file"
      echo "[$(date -Iseconds)] DONE: $item_text" >> "$ALERTS"
      ;;
    reverted)
      body=$(printf "Status: code reverted to %s; agent's claim of done did not survive verify.\n\nSummary: %s\n\nNext steps: %s\n\nAcceptance (last reported): %s" \
        "$pre_sha" "$summary" "${next_steps:-(none recorded)}" "${acceptance:-(none recorded)}")
      loop_commit "Unsuccessful ship" "$feature_num" "verify reverted: $summary" "$body"
      echo "[$(date -Iseconds)] REVERTED: $item_text (attempt $attempt)" >> "$ALERTS"
      ;;
    no|*)
      sed -i "${line_no}s/- \[ \]/- [!]/" "$QUEUE"
      body=$(printf "Status: verify inconclusive ('%s'); code reverted to %s.\n\nSummary: %s\n\nNext steps: %s" \
        "$verified" "$pre_sha" "$summary" "${next_steps:-(needs manual review)}")
      loop_commit "Unsuccessful ship" "$feature_num" "verify broken/inconclusive: $summary" "$body"
      echo "[$(date -Iseconds)] BROKEN: $item_text (verify='$verified')" >> "$ALERTS"
      rm -f "$attempt_file"
      ;;
  esac
  sleep "$SLEEP_BETWEEN"
done
